-- Migration 0003: RBAC Foundation (additive step)
-- DDL generated by Prisma; seed data and data migration added manually.
--
-- What this migration does:
--   1. Adds roles, permissions, and role_permissions tables
--   2. Adds nullable role_id column to users (FK to roles)
--   3. Seeds 3 system roles: SUPER_ADMIN, ADMIN, VIEWER
--   4. Seeds 18 permissions across 4 modules: users, roles, org, audit
--   5. Assigns permissions to each system role per the approved matrix
--   6. Backfills role_id for all existing users from the legacy role enum
--      (UserRole.ADMIN → SUPER_ADMIN, UserRole.USER → VIEWER)
--
-- The legacy role column and user_role enum are NOT removed here.
-- Migration 0004 makes role_id NOT NULL and removes the legacy column/type.
-- Do not run migration 0004 until this migration's data backfill is verified.

-- AlterTable
ALTER TABLE "users" ADD COLUMN     "role_id" UUID;

-- CreateTable
CREATE TABLE "roles" (
    "id" UUID NOT NULL,
    "code" VARCHAR(50) NOT NULL,
    "name" VARCHAR(200) NOT NULL,
    "description" VARCHAR(500),
    "is_system" BOOLEAN NOT NULL DEFAULT false,
    "is_active" BOOLEAN NOT NULL DEFAULT true,
    "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "updated_at" TIMESTAMPTZ(3) NOT NULL,

    CONSTRAINT "roles_pkey" PRIMARY KEY ("id")
);

-- CreateTable
CREATE TABLE "permissions" (
    "id" UUID NOT NULL,
    "code" VARCHAR(100) NOT NULL,
    "name" VARCHAR(200) NOT NULL,
    "description" VARCHAR(500),
    "module" VARCHAR(50) NOT NULL,
    "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "permissions_pkey" PRIMARY KEY ("id")
);

-- CreateTable
CREATE TABLE "role_permissions" (
    "role_id" UUID NOT NULL,
    "permission_id" UUID NOT NULL,
    "created_at" TIMESTAMPTZ(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT "role_permissions_pkey" PRIMARY KEY ("role_id","permission_id")
);

-- CreateIndex
CREATE UNIQUE INDEX "roles_code_key" ON "roles"("code");

-- CreateIndex
CREATE UNIQUE INDEX "permissions_code_key" ON "permissions"("code");

-- CreateIndex
CREATE INDEX "permissions_module_idx" ON "permissions"("module");

-- CreateIndex
CREATE INDEX "users_role_id_idx" ON "users"("role_id");

-- AddForeignKey
ALTER TABLE "role_permissions" ADD CONSTRAINT "role_permissions_role_id_fkey" FOREIGN KEY ("role_id") REFERENCES "roles"("id") ON DELETE RESTRICT ON UPDATE CASCADE;

-- AddForeignKey
ALTER TABLE "role_permissions" ADD CONSTRAINT "role_permissions_permission_id_fkey" FOREIGN KEY ("permission_id") REFERENCES "permissions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;

-- AddForeignKey
ALTER TABLE "users" ADD CONSTRAINT "users_role_id_fkey" FOREIGN KEY ("role_id") REFERENCES "roles"("id") ON DELETE RESTRICT ON UPDATE CASCADE;

-- Integrity constraints (manually added — Prisma does not generate CHECK constraints)
ALTER TABLE "roles"
    ADD CONSTRAINT "roles_code_format_check"
        CHECK ("code" = upper("code") AND "code" ~ '^[A-Z][A-Z0-9_]{1,49}$'),
    ADD CONSTRAINT "roles_name_not_blank_check"
        CHECK (length(btrim("name")) > 0);

ALTER TABLE "permissions"
    ADD CONSTRAINT "permissions_code_format_check"
        CHECK ("code" ~ '^[a-z][a-z0-9]*(\.[a-z][a-z0-9_]*)*$'),
    ADD CONSTRAINT "permissions_name_not_blank_check"
        CHECK (length(btrim("name")) > 0),
    ADD CONSTRAINT "permissions_module_not_blank_check"
        CHECK (length(btrim("module")) > 0);

