-- Seed: role_permission assignments

-- SUPER_ADMIN receives all 18 permissions
INSERT INTO "role_permissions" ("role_id", "permission_id")
SELECT r.id, p.id
FROM "roles" r
CROSS JOIN "permissions" p
WHERE r.code = 'SUPER_ADMIN';

-- ADMIN receives 15 permissions:
--   all user-management + org-management + roles.read + audit.read
--   excludes: roles.create, roles.update, roles.assign_permissions
INSERT INTO "role_permissions" ("role_id", "permission_id")
SELECT r.id, p.id
FROM "roles" r
JOIN "permissions" p ON p.code IN (
    'users.read', 'users.create', 'users.update', 'users.assign_role',
    'users.activate', 'users.reset_password', 'users.unlock',
    'roles.read',
    'org.departments.read', 'org.departments.write',
    'org.plants.read', 'org.plants.write',
    'org.locations.read', 'org.locations.write',
    'audit.read'
)
WHERE r.code = 'ADMIN';

-- VIEWER receives 5 permissions (read-only)
INSERT INTO "role_permissions" ("role_id", "permission_id")
SELECT r.id, p.id
FROM "roles" r
JOIN "permissions" p ON p.code IN (
    'users.read',
    'roles.read',
    'org.departments.read',
    'org.plants.read',
    'org.locations.read'
)
WHERE r.code = 'VIEWER';

-- Data migration: backfill role_id for all existing users from the legacy role enum.
-- Runs after seed data so role UUIDs are available for lookup by code.
-- UserRole.ADMIN → SUPER_ADMIN (privileged users retain highest access)
-- UserRole.USER  → VIEWER     (standard users become read-only)
UPDATE "users"
SET "role_id" = (SELECT "id" FROM "roles" WHERE "code" = 'SUPER_ADMIN')
WHERE "role" = 'ADMIN';

UPDATE "users"
SET "role_id" = (SELECT "id" FROM "roles" WHERE "code" = 'VIEWER')
WHERE "role" = 'USER';
